SELECT MONTH(order_date) AS month,
       IFNULL(SUM(total_price), 0) AS current_price
  FROM crm_contract
 WHERE deleted = 0
   AND audit_status = ${@cn.iocoder.yudao.module.crm.enums.common.CrmAuditStatusEnum@APPROVE.status}
   AND owner_user_id IN

            #{userId}

   AND YEAR(order_date) = #{year}
 GROUP BY MONTH(order_date)

SELECT MONTH(return_time) AS month,
       IFNULL(SUM(price), 0) AS current_price
  FROM crm_receivable
 WHERE deleted = 0
   AND audit_status = ${@cn.iocoder.yudao.module.crm.enums.common.CrmAuditStatusEnum@APPROVE.status}
   AND owner_user_id IN

            #{userId}

   AND YEAR(return_time) = #{year}
 GROUP BY MONTH(return_time)
